// Brand glyph helper: monochrome, currentColor, 24x24 viewBox (Simple Icons path data).
function Brand({ d, label, ...props }) {
  return (
    <svg viewBox="0 0 24 24" width="18" height="18" fill="currentColor" aria-hidden="true" {...props}>
      <path d={d} />
    </svg>
  );
}

